SELECT message_id, message_type, title, content, is_read, created_at, read_at, link, COALESCE(priority, 0) as priority FROM system_message
AND user_id = #{query.userId}
AND message_type = #{query.type}
AND is_read = #{query.read}
AND (expires_at IS NULL OR expires_at > NOW())
ORDER BY priority DESC, created_at DESC

